import React, { useState } from "react";

function SOP() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule1 = async () => {
    setLoading(true);
    try {
      const res = await fetch("http://localhost:5000/module1");
      const data = await res.json();
      setResult(data);
    } catch {
      alert("Backend error");
    }
    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>
      <button onClick={runModule1}>Run Module 1</button>

      {loading && <p>Processing...</p>}

      {result?.status === "success" && (
        <div>
          <h3>Output</h3>

          <p>NPSV Length: {result?.data?.npsv_length}</p>

          <p>
            Segments Shape:{" "}
            {result?.data?.segments_shape
              ? result.data.segments_shape.join(", ")
              : "Not available"}
          </p>

          <h3>Full NPSV Table</h3>

          <div
            style={{
              height: "400px",
              overflowY: "scroll",
              border: "1px solid black",
              marginTop: "10px",
            }}
          >
            <table border="1" width="100%">
              <thead>
                <tr>
                  <th>Index</th>
                  <th>NPSV Value</th>
                </tr>
              </thead>

              <tbody>
                {result?.data?.npsv?.map((value, index) => (
                  <tr key={index}>
                    <td>{index}</td>
                    <td>{value.toFixed(6)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

export default SOP;
